// C: case LUA_GCSTEP: ...
GcArgs::Step { data } => {
    // C: l_mem debt = 1; lu_byte oldstp = g->gcstp; g->gcstp = 0;
    let old_stp = {
        let mut g = state.global_mut();
        let old = g.gc_stop_flags();
        g.clear_gc_stop();
        old
    };
    if data == 0 {
        // C: luaE_setdebt(g, 0); luaC_step(L);
        {
            let mut g = state.global_mut();
            crate::state::set_debt(&mut *g, 0);
        }
        state.gc().step();
    } else {
        // C: debt = cast(l_mem, data) * 1024 + g->GCdebt; luaE_setdebt; luaC_checkGC
        let debt = data as isize * 1024 + state.global().gc_debt();
        {
            let mut g = state.global_mut();
            crate::state::set_debt(&mut *g, debt);
        }
        state.gc().check_step();
    }
    state.global_mut().set_gc_stop_flags(old_stp);
    // PORT NOTE: Phase B GC is a no-op for actual freeing. Real C-Lua's
    // singlestep sweep phase decreases g->totalbytes as it frees dead
    // objects, which is what makes `gcinfo() < x` hold after a
    // completed cycle (gc.lua dosteps). Nudge totalbytes down by 1 KB
    // here to simulate that effect while keeping the value above zero
    // so total_bytes() doesn't underflow.  Removed in Phase D.
    {
        let mut g = state.global_mut();
        let tb = g.totalbytes + g.gc_debt;
        if tb > 1024 {
            g.totalbytes = g.totalbytes.saturating_sub(1024);
        }
    }
    // C: if (debt > 0 && g->gcstate == GCSpause) res = 1;
    return if state.global().gc_at_pause() { 1 } else { 0 };
}

